SELECT  FROM tb_time_entry


        AND user_id = #{userId}


        AND project_id = #{projectId}


        AND task_id = #{taskId}


        AND work_date >= #{startDate}


        AND work_date <= #{endDate}


        AND status = #{status}


ORDER BY work_date DESC, id DESC

SELECT status, COUNT(*) AS count, COALESCE(SUM(hours), 0) AS total_hours
FROM tb_time_entry


        AND user_id = #{userId}


        AND project_id = #{projectId}


GROUP BY status

mapper.update:
UPDATE tb_time_entry
task_id = #{taskId}, work_date = #{workDate}, hours = #{hours}, content = #{content}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT e.*, u.name AS user_name, p.name AS project_name, t.name AS task_name
FROM tb_time_entry e
JOIN tb_user u ON e.user_id = u.id
JOIN tb_project p ON e.project_id = p.id
LEFT JOIN tb_task t ON e.task_id = t.id

    AND e.user_id = #{userId}
    AND e.project_id = #{projectId}
    AND e.task_id = #{taskId}
    AND e.work_date >= #{startDate}
    AND e.work_date <= #{endDate}
    AND e.status = #{status}

ORDER BY e.work_date DESC, e.id DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM tb_time_entry e

    AND e.user_id = #{userId}
    AND e.project_id = #{projectId}
    AND e.task_id = #{taskId}
    AND e.work_date >= #{startDate}
    AND e.work_date <= #{endDate}
    AND e.status = #{status}
